SELECT AVG(severity) AS average_severity
FROM patient_symptoms
WHERE symptom_id = (SELECT symptom_id FROM symptoms WHERE symptom_name = 'alertness');

SELECT symptom_name, description
FROM symptoms
WHERE severity_scale != 'Mild';

SELECT COUNT(patient_id) AS number_of_participants
FROM trial_patients
WHERE trial_id = 0;

SELECT COUNT(patient_id) AS patient_count
FROM trial_patients
WHERE trial_id = (SELECT trial_id FROM clinical_trials WHERE trial_name = 'Muscular Dystrophy Research');
